    style EvaluationMetric fill:#2d4a22,stroke:#27ae60,color:#fff
    style OutputResult fill:#1a3a4a,stroke:#3498db,color:#fff

    Start([Start]) --> A[Define Benchmark Goal];
    A --> B[/Initial Research on LLM Agent Misuse/];

    subgraph TaskCreation["Task Creation"]
        B --> C[Identify 11 Harm Categories];
        C --> D[Manually Write 10 Base Behaviors per Category];
        D --> E{Are Behaviors Digitally Realizable?};
        E -- Yes --> F[Review Behaviors by Separate Human Reviewers];
        E -- No --> D;
        F --> G[Create 110 Base Malicious Agent Tasks];
        G --> H[Augment Base Tasks (440 Total Tasks)];
        H --> H1[Detailed Tasks];
        H --> H2[Open-Ended Tasks];
        H --> H3[Hint Included Tasks];
        G --> I[Rewrite Harmful Tasks to Benign Counterparts];
    end

    subgraph ToolDevelopment["Tool Development"]
        I --> J[Develop Synthetic Tools using Inspect Framework];
        J --> K[Implement Standalone Functions without Side Effects];
        K --> L[Use LLMs for Long-Form Content Generation by Tools];
        L --> M{Are Tools Designed for Self-Correction?};
        M -- Yes --> N[Integrate Tools with Tasks];
        M -- No --> K;
    end

    subgraph GradingSystem["Grading System"]
        N --> O[Define Fine-Grained Grading Rubrics];
        O --> P[Manually Write Predefined Scoring Conditions];
        P --> Q{Partial Credit for Some Criteria?};
        Q -- Yes --> R[Use Semantic LLM Judge for Narrow Semantic Checks];
        R --> S[Implement Refusal Judge for Agent Refusal Rate];
        S --> T[Apply Refusal Judge on All Agent Messages];
    end

    subgraph DatasetManagement["Dataset Management"]
        T --> U[Split Dataset into Validation (10%), Public Test (60%), Private Test (30%)];
        U --> V[Add Canary String to Prevent Contamination];
        V --> W[Deploy Private Test Set on Isolated Environment];
    end

    subgraph Evaluation["Evaluation"]
        W --> X[Evaluate LLM Agents with Direct Prompting];
        X --> Y[Apply Forced Tool Calls Jailbreak Method];
        Y --> Z[Apply Universal Jailbreak Template Method];
        Z --> AA[Measure Harm Scores and Refusal Rates];
        AA --> BB[Compare Jailbroken vs. Benign Performance];
    end

    BB --> End([End]);

