    Start([开始]) --> A[定义基准目标];
    A --> B[/LLM 代理滥用初步研究/];

    subgraph TaskCreation["任务创建"]
        B --> C[识别 11 种危害类别];
        C --> D[每类别手动编写 10 个基础行为];
        D --> E{行为是否可数字化实现?};
        E -- 是 --> F[由独立人工评审员审查行为];
        E -- 否 --> D;
        F --> G[创建 110 个基础恶意代理任务];
        G --> H[增强基础任务 (总计 440 个任务)];
        H --> H1[详细任务];
        H --> H2[开放式任务];
        H --> H3[包含提示的任务];
        G --> I[将有害任务重写为良性对应任务];
    end

    subgraph ToolDevelopment["工具开发"]
        I --> J[使用 Inspect 框架开发合成工具];
        J --> K[实现无副作用的独立功能];
        K --> L[使用 LLM 生成工具的长篇内容];
        L --> M{工具是否设计用于自我纠正?};
        M -- 是 --> N[将工具与任务集成];
        M -- 否 --> K;
    end

    subgraph GradingSystem["评分系统"]
        N --> O[定义细粒度评分标准];
        O --> P[手动编写预定义评分条件];
        P --> Q{部分标准是否可获得部分分数?};
        Q -- 是 --> R[使用语义 LLM 判官进行狭义语义检查];
        R --> S[实现代理拒绝率判官];
        S --> T[对所有代理消息应用拒绝判官];
    end

    subgraph DatasetManagement["数据集管理"]
        T --> U[将数据集分为验证集 (10%)、公共测试集 (60%)、私有测试集 (30%)];
        U --> V[添加金丝雀字符串以防止污染];
        V --> W[在隔离环境中部署私有测试集];
    end

    subgraph Evaluation["评估"]
        W --> X[使用直接提示评估 LLM 代理];
        X --> Y[应用强制工具调用越狱方法];
        Y --> Z[应用通用越狱模板方法];
        Z --> AA[测量危害分数和拒绝率];
        AA --> BB[比较越狱与良性性能];
    end

    BB --> End([结束]);

