flowchart_en:
flowchart TD
    subgraph Phase["Phase 1: Data Sourcing and Collection"]
        A([Start Benchmark Creation]) --> B{Identify Information Needs};
        B -->|Biomedical Experts| C[/Source Real-World Questions/];
        C --> D(Collect New Biomedical Questions);
        D -->|~340 questions| E{Categorize Question Types};
        E -->|Yes/No| F[Yes/No Questions];
        E -->|Factoid| G[Factoid Questions];
        E -->|List| H[List Questions];
        E -->|Summary| I[Summary Questions];
    end

    subgraph Phase2["Phase 2: Annotation and Golden Answer Generation"]
        J[Existing Training Data] -->|5,389 questions| K(Combine with New Questions);
        F --> K;
        G --> K;
        H --> K;
        I --> K;
        K --> L(Expert Annotation: Documents);
        style L fill:#3d1a78,stroke:#9b59b6,color:#fff
        L -->|Identify relevant PubMed articles| M(Expert Annotation: Snippets);
        style M fill:#3d1a78,stroke:#9b59b6,color:#fff
        M -->|Extract relevant text passages| N(Expert Annotation: Exact Answers);
        style N fill:#3d1a78,stroke:#9b59b6,color:#fff
        N -->|Provide Yes/No, Factoid, or List answers| O(Expert Annotation: Ideal Answers);
        style O fill:#3d1a78,stroke:#9b59b6,color:#fff
        O -->|Write paragraph-sized summary| P[/Annotated Question Dataset/];
    end

    subgraph Phase3["Phase 3: Quality Control and Dataset Finalization"]
        P --> Q{Initial Quality Check};
        style Q fill:#7d2a2a,stroke:#e74c3c,color:#fff
        Q -->|Pass| R(Cross-Annotation Review);
        style R fill:#7d2a2a,stroke:#e74c3c,color:#fff
        Q -->|Fail| L;
        R -->|Inconsistencies| S{Adjudication};
        style S fill:#7d2a2a,stroke:#e74c3c,color:#fff
        R -->|Consistent| T(Finalize Golden Annotations);
        S --> T;
        T --> U(Split into Training and Test Sets);
        style U fill:#1b4332,stroke:#52b788,color:#fff
        U -->|5,389 for training| V[/Final Training Dataset/];
        style V fill:#1a3a4a,stroke:#3498db,color:#fff
        U -->|340 for testing| W(Partition Test Set into Batches);
        style W fill:#1b4332,stroke:#52b788,color:#fff
        W -->|4 batches of ~85 questions| X[/Final Test Datasets/];
        style X fill:#1a3a4a,stroke:#3498db,color:#fff
    end

    subgraph Phase4["Phase 4: Benchmark Deployment and Evaluation"]
        V --> Y(Release Training Data to Participants);
        style Y fill:#0d3b66,stroke:#4a90d9,color:#fff
        X --> Z(Release Test Batches Bi-weekly);
        style Z fill:#0d3b66,stroke:#4a90d9,color:#fff
        Z --> AA(Participants Submit System Predictions);
        AA --> BB{Evaluation of Submissions};
        style BB fill:#2d4a22,stroke:#27ae60,color:#fff
        P --> BB;
        BB -->|Compare against Golden Answers| CC(Calculate Performance Metrics);
        style CC fill:#2d4a22,stroke:#27ae60,color:#fff
        CC --> DD[/Evaluation Results/];
        style DD fill:#1a3a4a,stroke:#3498db,color:#fff
        DD --> EE([End of Benchmark Cycle]);
    end

