flowchart TD
    subgraph BenchmarkConstruction[CC-OCR Benchmark Construction Process]
        direction TD

        subgraph Phase1[Phase 1: Data Sourcing and Collection]
            direction TD
            A([Start]) --> B{Data Sourcing Strategy};
            B --> C1[/Existing Benchmarks (e.g., TotalText, IC15, FUNSD)/];
            B --> C2[/Re-annotation of Datasets (e.g., MTVQA, LAION-5B)/];
            B --> C3[/Newly Collected Data (In-house, Real-world)/];
            C1 --> D(Collect English Data);
            C2 --> D;
            C3 --> D;
            D --> E{Select Data Types};
            E -->|Natural Scene Images| F1[/1850 Natural Scene Images/];
            E -->|Real-world Documents| F2[/350 Document Images/];
            E -->|Web Images| F3[/550 Web Images/];
            E -->|Handwritten Images| F4[/Handwritten Data/];
        end

        subgraph Phase2[Phase 2: Data Pre-processing and Categorization]
            direction TD
            F1 & F2 & F3 & F4 --> G{Categorize by OCR Task};
            G --> H1(Multi-Scene OCR);
            G --> H2(Multilingual OCR);
            G --> H3(Document Parsing);
            G --> H4(Key Information Extraction);

            H1 --> I1[/1850 Natural Scene, 350 Docs, 550 Web Images/];
            H2 --> I2[/10 real-shot docs & 140 scene images per language/];
            H3 --> I3[/300 Docs, 300 Tables, 200 Formulas/];
            H4 --> I4[/1008 Constrained, 1000 Open-category Images/];
        end

        subgraph Phase3[Phase 3: Annotation and Labeling]
            direction TD
            I1 & I2 & I3 & I4 --> J{Annotation Strategy};
            J --> K1(Model-based Pre-annotation);
            K1 --> L{Iterative Refinement Process};
            L --> M(Cross-validation by different models);
            M --> N(Manual Correction);
            N --> O{Select Annotation Format};
            O -->|Texts| P1(Text Transcriptions & Word-level Grounding);
            O -->|Documents| P2(LaTeX format via Mathpix-Markdown-IT);
            O -->|Structured Tables| P3(HTML format for row/column span);
            O -->|Information Extraction| P4(Standardized JSON for KIE);
            P2 --> P2_1(Generate pseudo-labels for handwritten formulas);
            P2_1 --> P2_2(Manual correction of formula errors);
        end

        subgraph Phase4[Phase 4: Quality Control and Validation]
            direction TD
            P1 & P2_2 & P3 & P4 --> Q{Quality Control};
            Q --> R(Review and Verification by OCR Experts);
            R --> S(Verification by Large Language Models);
            S --> T{Final Validation};
            T -->|Pass| U([End]);
            T -->|Fail| L;
        end

        subgraph Phase5[Phase 5: Final Benchmark Composition]
            direction TD
            U --> V[/Final CC-OCR Benchmark (7,058 images)/];
            V --> W{Benchmark Tracks};
            W --> X1(Multi-Scene Text Reading);
            W --> X2(Multilingual Text Reading);
            W --> X3(Document Parsing);
            W --> X4(Key Information Extraction);
            X1 & X2 & X3 & X4 --> Y(Evaluation Metrics Definition);
            Y --> Z1[/Eval-Trans & Eval-Pos for OCR/];
            Y --> Z2[/Normalized Edit Distance (NED) for Parsing/];
            Y --> Z3[/Tree Edit Distance-based Similarity (TEDS) for Tables/];
            Y --> Z4[/Field-level F1 Score for KIE/];
        end
    end

