        A -->|Target: Coding Ability| B;
    end

    subgraph Phase["Phase 2: Data Collection"]
        C(Collect problems from CodeForces API);
        D{Problem type filter?};
        B --> C;
        C --> D;
        D -->|Yes: Algorithmic/Implementation| E(Select relevant problems);
        D -->|No| F(Discard irrelevant problems);
    end

