        P{Annotation consistency check};
        Q(Manual review of a sample of annotated problems);
        N --> O;
        O --> P;
        P -->|Consistent| Q;
        P -->|Inconsistent| L;
        Q -->|Pass| R(Approve for final benchmark);
        Q -->|Fail| L;
    end

    subgraph Phase["Phase 6: Final Benchmark Creation"]
        S(Compile final set of problems and solutions);
        T(Create evaluation scripts);
        U(Define performance metrics: Pass@k, execution time);
        R --> S;
        S --> T;
        T --> U;
