    subgraph Phase["阶段 1: 数据来源"]
        A([开始: 定义基准目标]);
        B[/CodeForces 第二赛区问题集/];
        A -->|目标: 编码能力| B;
    end

    subgraph Phase["阶段 2: 数据收集"]
        C(从CodeForces API收集问题);
        D{问题类型过滤?};
        B --> C;
        C --> D;
        D -->|是: 算法/实现| E(选择相关问题);
        D -->|否| F(丢弃不相关问题);
    end

    subgraph Phase["阶段 3: 数据处理和过滤"]
        G(提取问题陈述、解决方案和测试用例);
        H{代码语言过滤?};
        I{解决方案正确性检查};
        E --> G;
        G --> H;
        H -->|是: C++, Java, Python| I;
        H -->|否: 其他语言| G;
        I -->|通过| J(标准化代码格式);
        I -->|失败| G;
    end

    subgraph Phase["阶段 4: 注释和标记"]
        K(生成分步函数解释);
        L(用功能步骤注释代码);
        M{人工验证注释?};
        J --> K;
        K --> L;
        L --> M;
        M -->|是: 专家验证| N(最终确定注释数据集);
        M -->|否: 需要修正| L;
    end

    subgraph Phase["阶段 5: 质量控制"]
        O(对注释进行自动化质量检查);
        P{注释一致性检查};
        Q(人工审查部分注释问题样本);
        N --> O;
        O --> P;
        P -->|一致| Q;
        P -->|不一致| L;
        Q -->|通过| R(批准用于最终基准);
        Q -->|失败| L;
    end

    subgraph Phase["阶段 6: 最终基准创建"]
        S(编译最终问题和解决方案集);
        T(创建评估脚本);
        U(定义性能指标: Pass@k, 执行时间);
        R --> S;
        S --> T;
        T --> U;
        V([结束: CF-Div2-Stepfun 基准]);
        U --> V;
    end

    style A fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style V fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style B fill:#0d3b66,stroke:#4a90d9,color:#fff
