flowchart_en:
flowchart TD
    subgraph "Phase 1: Task Definition"
        A([Start]) --> B(Define 35 CXR Interpretation Tasks);
    end

    subgraph "Phase 2: Data Collection"
        B --> C[/Collect 32 Public CXR Datasets<br>(MIMIC-CXR, CheXpert, PadChest, etc.)/];
    end

    subgraph "Phase 3: Data Engineering"
        C --> D{Inspect and Preprocess Data};
        D --> E(Manual Quality Control by Experts);
        D --> F(Automated Data Engineering Pipeline);
    end

    subgraph "Phase 4: CheXinstruct Dataset Compilation"
        E --> G(Compile CheXinstruct Dataset);
        F --> G;
        G --> H(Pair 35 Tasks with Source Datasets);
        H --> I(Generate Questions and Answers for each task);
        I --> J[/8.5 Million Training Samples/];
    end

    subgraph "Phase 5: CheXagent Model Training"
        J --> K(Train CheXagent Vision-Language Model);
    end

    subgraph "Phase 6: CheXbench Benchmark Creation"
        K --> L(Create CheXbench Evaluation Benchmark);
        L --> M{Define 8 Task Types for Evaluation};
        M --> N(3 Image Perception Tasks);
        M --> O(3 Image-Text Reasoning Tasks);
        M --> P(2 Text Generation Tasks);
    end

    subgraph "Phase 7: Model Evaluation"
        P --> Q(Evaluate CheXagent on CheXbench);
        N --> Q;
        O --> Q;
        Q --> R{Compare with other Foundation Models<br>(MAIRA-1, Med-PaLM-M, GPT-4V)};
    end

    subgraph "Phase 8: Clinical Evaluation"
        R --> S(Conduct Reader Study with 8 Radiologists);
        S --> T{Compare CheXagent-drafted vs. Resident-drafted reports};
        T --> U(Measure Time Savings and Report Quality);
        U --> V(Assess Real-world Utility);
    end

    subgraph "Phase 9: Final Output"
        V --> W([End: CheXBench Benchmark]);
    end

    style A fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style W fill:#1a1a2e,stroke:#4a90d9,color:#fff
