flowchart_zh:
flowchart TD
    subgraph "阶段 1: 任务定义"
        A([开始]) --> B(定义 35 个胸部X光解读任务);
    end

    subgraph "阶段 2: 数据收集"
        B --> C[/收集 32 个公开胸部X光数据集<br>(MIMIC-CXR, CheXpert, PadChest 等)/];
    end

    subgraph "阶段 3: 数据工程"
        C --> D{检查和预处理数据};
        D --> E(专家手动质量控制);
        D --> F(自动化数据工程流程);
    end

    subgraph "阶段 4: CheXinstruct 数据集编译"
        E --> G(编译 CheXinstruct 数据集);
        F --> G;
        G --> H(将 35 个任务与源数据集配对);
        H --> I(为每个任务生成问题和答案);
        I --> J[/850 万训练样本/];
    end

    subgraph "阶段 5: CheXagent 模型训练"
        J --> K(训练 CheXagent 视觉-语言模型);
    end

    subgraph "阶段 6: CheXbench 基准创建"
        K --> L(创建 CheXbench 评估基准);
        L --> M{定义 8 种评估任务类型};
        M --> N(3 种图像感知任务);
        M --> O(3 种图像-文本推理任务);
        M --> P(2 种文本生成任务);
    end

    subgraph "阶段 7: 模型评估"
        P --> Q(在 CheXbench 上评估 CheXagent);
        N --> Q;
        O --> Q;
        Q --> R{与其他基础模型比较<br>(MAIRA-1, Med-PaLM-M, GPT-4V)};
    end

    subgraph "阶段 8: 临床评估"
        R --> S(进行 8 名放射科医生阅读研究);
        S --> T{比较 CheXagent 起草与住院医师起草报告};
        T --> U(衡量时间节省和报告质量);
        U --> V(评估实际应用价值);
    end

    subgraph "阶段 9: 最终输出"
        V --> W([结束: CheXBench 基准]);
    end

