flowchart_en:
flowchart TD
    style StartEnd fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style DataCollection fill:#0d3b66,stroke:#4a90d9,color:#fff
    style ProcessingFiltering fill:#1b4332,stroke:#52b788,color:#fff
    style AnnotationLabeling fill:#3d1a78,stroke:#9b59b6,color:#fff
    style QualityControl fill:#7d2a2a,stroke:#e74c3c,color:#fff
    style EvaluationMetrics fill:#2d4a22,stroke:#27ae60,color:#fff
    style OutputResult fill:#1a3a4a,stroke:#3498db,color:#fff

    Start([Start Benchmark Construction])
    Start --> Phase1_Start

    subgraph Phase1["Phase 1: Data Collection & Initial Verification"]
        Phase1_Start --> A[AI Trainers Create Q&A Pairs]
        A --> B{Q&A Criteria Met?}
        B -- No --> A
        B -- Yes --> C[Provide Webpage Link for Evidence]
        C --> D{Challenging? (GPT-4/3.5 Responses)}
        D -- No --> A
        D -- Yes --> E[Q Answerable by Dec 31, 2023?]
        E -- No --> A
        E -- Yes --> F[Independent AI Trainer Answers Q]
        F --> G{Answers Match?}
        G -- No --> A
        G -- Yes --> H[/Initial Q&A Dataset/]
    end

    H --> Phase2_Start

    subgraph Phase2["Phase 2: Data Quality & Refinement"]
        Phase2_Start --> I[ChatGPT Classifiers Detect Criteria Violations]
        I --> J{Violations Detected?}
        J -- Yes --> K[Questions Sent for Revision]
        K --> I
        J -- No --> L[ChatGPT Rewrites Q for Grammar/Punctuation]
        L --> M[Independent AI Trainers Verify Timelessness & Single Answer]
        M --> N{Timeless & Single Answer?}
        N -- No --> K
        N -- Yes --> O{Two Trainers Agree on Answer?}
        O -- No --> K
        O -- Yes --> P{Two Unique Domain Names for Sources?}
        P -- No --> K
        P -- Yes --> Q[/Finalized Q&A Dataset (4,326 Questions)/]
    end

    Q --> Phase3_Start

    subgraph Phase3["Phase 3: Final Quality Check & Diversity Analysis"]
        Phase3_Start --> R[Randomly Select 1,000 Examples]
        R --> S[Third Trainer Answers 1,000 Examples]
        S --> T[ChatGPT Grader Evaluates (94.4% Correct)]
        T --> U{Incorrect Answers (5.6%)?}
        U -- Yes --> V[Manual Examination of Incorrect Answers]
        V --> W{False Negatives (15)?}
        W -- Yes --> T
        W -- No --> X{Actual Errors (41)?}
        X -- Yes --> Y[Analyze Error Causes (Incomplete, Contradictory Sources)]
        Y --> Z[Estimate Benchmark Error Rate (~3%)]
        Z --> AA[ChatGPT Tags Questions for Topics]
        AA --> BB[ChatGPT Classifies Answer Types]
        BB --> CC[Analyze Source Diversity]
        CC --> End([End Benchmark Construction])
    end

    classDef StartEnd fill:#1a1a2e,stroke:#4a90d9,color:#fff;
    classDef DataCollection fill:#0d3b66,stroke:#4a90d9,color:#fff;
    classDef ProcessingFiltering fill:#1b4332,stroke:#52b788,color:#fff;
    classDef AnnotationLabeling fill:#3d1a78,stroke:#9b59b6,color:#fff;
    classDef QualityControl fill:#7d2a2a,stroke:#e74c3c,color:#fff;
    classDef EvaluationMetrics fill:#2d4a22,stroke:#27ae60,color:#fff;
    classDef OutputResult fill:#1a3a4a,stroke:#3498db,color:#fff;

    class Start,End StartEnd;
    class A,F DataCollection;
    class I,L,R,S,T,V,Y,AA,BB,CC ProcessingFiltering;
    class B,D,E,G,J,N,O,P,U,W,X QualityControl;
    class H,Q OutputResult;
    class Z EvaluationMetrics;

flowchart_zh:
flowchart TD
    style StartEnd fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style DataCollection fill:#0d3b66,stroke:#4a90d9,color:#fff
    style ProcessingFiltering fill:#1b4332,stroke:#52b788,color:#fff
    style AnnotationLabeling fill:#3d1a78,stroke:#9b59b6,color:#fff
    style QualityControl fill:#7d2a2a,stroke:#e74c3c,color:#fff
    style EvaluationMetrics fill:#2d4a22,stroke:#27ae60,color:#fff
    style OutputResult fill:#1a3a4a,stroke:#3498db,color:#fff

    Start([开始基准测试构建])
    Start --> Phase1_Start

    subgraph Phase1["阶段 1: 数据收集与初步验证"]
        Phase1_Start --> A[AI 训练师创建问答对]
        A --> B{符合问答标准?}
        B -- 否 --> A
        B -- 是 --> C[提供网页链接作为证据]
        C --> D{具有挑战性? (GPT-4/3.5 回复)}
        D -- 否 --> A
        D -- 是 --> E[问题在 2023 年 12 月 31 日前可回答?]
        E -- 否 --> A
        E -- 是 --> F[独立 AI 训练师回答问题]
        F --> G{答案匹配?}
        G -- 否 --> A
        G -- 是 --> H[/初始问答数据集/]
    end

    H --> Phase2_Start

    subgraph Phase2["阶段 2: 数据质量与完善"]
        Phase2_Start --> I[ChatGPT 分类器检测违规]
        I --> J{检测到违规?}
        J -- 是 --> K[问题发送修订]
        K --> I
        J -- 否 --> L[ChatGPT 重写问题以改进语法/标点]
        L --> M[独立 AI 训练师验证时效性与单一答案]
        M --> N{时效性与单一答案?}
        N -- 否 --> K
        N -- 是 --> O{两位训练师同意答案?}
        O -- 否 --> K
        O -- 是 --> P{来源有两个独立域名?}
        P -- 否 --> K
        P -- 是 --> Q[/最终问答数据集 (4,326 个问题)/]
    end

    Q --> Phase3_Start

    subgraph Phase3["阶段 3: 最终质量检查与多样性分析"]
        Phase3_Start --> R[随机选择 1,000 个示例]
        R --> S[第三位训练师回答 1,000 个示例]
        S --> T[ChatGPT 评分器评估 (94.4% 正确)]
        T --> U{答案不正确 (5.6%)?}
        U -- 是 --> V[手动检查不正确答案]
        V --> W{假阴性 (15)?}
        W -- 是 --> T
        W -- 否 --> X{实际错误 (41)?}
        X -- 是 --> Y[分析错误原因 (不完整, 矛盾来源)]
        Y --> Z[估计基准错误率 (~3%)]
        Z --> AA[ChatGPT 标记问题主题]
        AA --> BB[ChatGPT 分类答案类型]
        BB --> CC[分析来源多样性]
        CC --> End([结束基准测试构建])
    end

    classDef StartEnd fill:#1a1a2e,stroke:#4a90d9,color:#fff;
    classDef DataCollection fill:#0d3b66,stroke:#4a90d9,color:#fff;
    classDef ProcessingFiltering fill:#1b4332,stroke:#52b788,color:#fff;
    classDef AnnotationLabeling fill:#3d1a78,stroke:#9b59b6,color:#fff;
    classDef QualityControl fill:#7d2a2a,stroke:#e74c3c,color:#fff;
    classDef EvaluationMetrics fill:#2d4a22,stroke:#27ae60,color:#fff;
    classDef OutputResult fill:#1a3a4a,stroke:#3498db,color:#fff;

    class Start,End StartEnd;
    class A,F DataCollection;
    class I,L,R,S,T,V,Y,AA,BB,CC ProcessingFiltering;
    class B,D,E,G,J,N,O,P,U,W,X QualityControl;
    class H,Q OutputResult;
    class Z EvaluationMetrics;

flowchart_en:
flowchart TD
    subgraph Phase["Phase 1: Data Sourcing & Collection"]
        A([Start]) --> B{Identify Data Sources};
        style A fill:#1a1a2e,stroke:#4a90d9,color:#fff
        B --> C[/Source 1: Academic Papers/];
        B --> D[/Source 2: Code Repositories/];
        B --> E[/Source 3: Web Text Corpora/];
        C --> F(Collect papers on reasoning & problem solving);
        D --> F;
        E --> F;
        style F fill:#0d3b66,stroke:#4a90d9,color:#fff
    end

    subgraph Phase2["Phase 2: Data Processing & Filtering"]
        F --> G{Initial Filtering Criteria};
        G -->|Length > 500 words| H(Filter by document length);
        style H fill:#1b4332,stroke:#52b788,color:#fff
        H --> I(Remove duplicates and boilerplate text);
        style I fill:#1b4332,stroke:#52b788,color:#fff
        I --> J{Content Quality Check};
        J -->|Passes| K(Select high-quality documents);
        style K fill:#1b4332,stroke:#52b788,color:#fff
        J -->|Fails| L(Discard low-quality documents);
        style L fill:#1b4332,stroke:#52b788,color:#fff
    end

    subgraph Phase3["Phase 3: Task Generation & Annotation"]
        K --> M(Generate candidate in-context learning tasks);
        style M fill:#3d1a78,stroke:#9b59b6,color:#fff
        M --> N{Annotation Guidelines};
        N --> O(Annotate tasks with demonstrations and expected outputs);
        style O fill:#3d1a78,stroke:#9b59b6,color:#fff
        O --> P(Create multiple-choice questions for evaluation);
        style P fill:#3d1a78,stroke:#9b59b6,color:#fff
    end

    subgraph Phase4["Phase 4: Quality Control"]
        P --> Q{Expert Review};
        Q -->|Approved| R(Accept annotated task);
        style R fill:#7d2a2a,stroke:#e74c3c,color:#fff
        Q -->|Rejected| S(Revise or discard task);
        style S fill:#7d2a2a,stroke:#e74c3c,color:#fff
        R --> T(Calculate inter-annotator agreement score);
        style T fill:#7d2a2a,stroke:#e74c3c,color:#fff
        T --> U{Agreement > 0.85?};
        U -->|Yes| V(Finalize task set);
        style V fill:#7d2a2a,stroke:#e74c3c,color:#fff
        U -->|No| S;
    end

    subgraph Phase5["Phase 5: Benchmark Finalization"]
        V --> W(Define evaluation metrics: Accuracy, F1-Score);
        style W fill:#2d4a22,stroke:#27ae60,color:#fff
        W --> X(Split data into train, validation, and test sets);
        style X fill:#2d4a22,stroke:#27ae60,color:#fff
        X --> Y[/Final CL-bench Dataset/];
        style Y fill:#1a3a4a,stroke:#3498db,color:#fff
        Y --> Z([End]);
        style Z fill:#1a1a2e,stroke:#4a90d9,color:#fff
    end

flowchart_zh:
flowchart TD
    subgraph Phase["阶段 1: 数据来源与收集"]
        A([开始]) --> B{识别数据来源};
        style A fill:#1a1a2e,stroke:#4a90d9,color:#fff
        B --> C[/来源 1: 学术论文/];
        B --> D[/来源 2: 代码仓库/];
        B --> E[/来源 3: 网络文本语料库/];
        C --> F(收集关于推理与问题解决的论文);
        D --> F;
        E --> F;
        style F fill:#0d3b66,stroke:#4a90d9,color:#fff
    end

    subgraph Phase2["阶段 2: 数据处理与筛选"]
        F --> G{初始筛选标准};
        G -->|长度 > 500 词| H(按文档长度筛选);
        style H fill:#1b4332,stroke:#52b788,color:#fff
        H --> I(删除重复项和样板文本);
        style I fill:#1b4332,stroke:#52b788,color:#fff
        I --> J{内容质量检查};
        J -->|通过| K(选择高质量文档);
        style K fill:#1b4332,stroke:#52b788,color:#fff
        J -->|未通过| L(丢弃低质量文档);
        style L fill:#1b4332,stroke:#52b788,color:#fff
    end

    subgraph Phase3["阶段 3: 任务生成与标注"]
        K --> M(生成候选上下文学习任务);
        style M fill:#3d1a78,stroke:#9b59b6,color:#fff
        M --> N{标注指南};
        N --> O(用示例和预期输出标注任务);
        style O fill:#3d1a78,stroke:#9b59b6,color:#fff
        O --> P(创建用于评估的多项选择题);
        style P fill:#3d1a78,stroke:#9b59b6,color:#fff
    end

    subgraph Phase4["阶段 4: 质量控制"]
        P --> Q{专家评审};
        Q -->|批准| R(接受已标注任务);
        style R fill:#7d2a2a,stroke:#e74c3c,color:#fff
        Q -->|驳回| S(修改或丢弃任务);
        style S fill:#7d2a2a,stroke:#e74c3c,color:#fff
        R --> T(计算标注者间一致性得分);
        style T fill:#7d2a2a,stroke:#e74c3c,color:#fff
        T --> U{一致性 > 0.85?};
        U -->|是| V(最终确定任务集);
        style V fill:#7d2a2a,stroke:#e74c3c,color:#fff
