            G -- 否 --> I(选择高质量提示);
            H --> I;
            I --> J(标准化工具规范);
        end
        subgraph Annotation & Labeling["标注与标记"]
            J --> K(人工标注: 预期工具调用);
            K --> L(人工标注: 预期工具输出);
            L --> M(交叉验证标注);
            M --> N{标注一致性达成?};
            N -- 否 --> O(重新标注并解决差异);
            N -- 是 --> P(最终确定真实标注);
            O --> P;
        end
        subgraph Quality Control & Validation["质量控制与验证"]
            P --> Q(构建基准实例);
            Q --> R(验证实例格式与一致性);
            R --> S(对样本实例进行专家评审);
            S --> T{实例通过评审?};
            T -- 否 --> U(迭代并修正实例);
            T -- 是 --> V(最终确定基准数据集);
            U --> V;
        end
        subgraph Evaluation Setup["评估设置"]
            V --> W(定义评估指标);
            W --> X(开发自动化评估工具);
            X --> Y(集成LLM工具使用模型);
        end
