flowchart TD
    subgraph Med-HALT Benchmark Construction
        A([Start]) --> B{Data Sourcing};

        subgraph Phase 1: Data Collection
            B --> C1[/MEDMCQA Dataset (India, 9515 MCQs)/];
            B --> C2[/Headqa Dataset (Spain, 4068 MCQs)/];
            B --> C3[/Medqa USMILE Dataset (US, 2801 MCQs)/];
            B --> C4[/Medqa Taiwan Dataset (Taiwan, 2482 MCQs)/];
            B --> C5[/PubMed Dataset (4916 Samples)/];
            C1 --> D(Combine into Raw MCQ Dataset);
            C2 --> D;
            C3 --> D;
            C4 --> D;
        end

        D --> E{Benchmark Test Generation};
        C5 --> E;

        subgraph Phase 2: Test Categories
            subgraph Reasoning Hallucination Tests (RHT)
                E --> F(Define RHT Tasks);
                F --> F1(Generate False Confidence Test Questions);
                F --> F2(Generate None-of-the-Above Test Questions);
                F --> F3(Generate Fake Questions Test);
                F1 --> G[/RHT Dataset (18,866 Samples)/];
                F2 --> G;
                F3 --> G;
            end

            subgraph Memory Hallucination Tests (MHT)
                E --> H(Define MHT Tasks);
                H --> H1(Generate PMID-to-Title Retrieval Task);
                H --> H2(Generate Title-to-Link Retrieval Task);
                H --> H3(Generate Abstract-to-Link Retrieval Task);
                H --> H4(Generate Link-to-Title Retrieval Task);
                H1 --> I[/MHT Dataset (4916 Samples)/];
                H2 --> I;
                H3 --> I;
                H4 --> I;
            end
        end

        G --> J{Quality Control & Validation};
        I --> J;

        subgraph Phase 3: Quality Control
            J --> K(Stratified Sampling of 30% of Data);
            K --> L{Perform Exploratory Analysis};
            L --> L1(Analyze Effect of Temperature);
            L --> L2(Analyze Effect of Few-shot Examples);
            L --> L3(Analyze Effect of Prompt Framing);
            L --> M(Categorize Questions by Reasoning Type);
            M --> N{Define Evaluation Metrics};
            N --> N1(Define Accuracy Metric);
            N --> N2(Define Pointwise Score Metric: +1 Correct, -0.25 Incorrect);
        end

        N1 --> O{Final Benchmark Assembly};
        N2 --> O;

        subgraph Phase 4: Final Benchmark
            O --> P[/Med-HALT Benchmark/];
            P --> Q([End: Benchmark Published]);
        end
    end

