flowchart_en:
flowchart TD
    subgraph Phase["Phase 1: Harmful Prompt Generation"]
        A0([Start]) --> A1;
        A1(Define Medical Safety based on AMA Principles of Medical Ethics) --> A2;
        A2{Select Generation Model} --> A3;
        A2 --> A4;
        A3(Use GPT-4 to generate harmful prompts) --> A5;
        A4(Use Llama-2-7b-chat with Greedy Coordinate Gradient attack) --> A6;
        A5 --> A7(Manually inspect and filter 900 harmful prompts);
        A6 --> A7;
        A7 --> A8[/med-harm-gpt4-full & med-harm-llama2-full/];
    end

    subgraph Phase["Phase 2: Safety Demonstration Creation"]
        A8 --> B1(Split harmful prompts into training and test sets);
        B1 --> B2[/MedSafety-Eval-GPT4 & MedSafety-Eval-Llama2/];
        B1 --> B3(Use GPT-4 to generate safe responses for training set prompts);
        B3 --> B4{Manual Verification}; 
        B4 -- Yes --> B5(Edit inadequate responses);
        B4 -- No --> B6;
        B5 --> B6(Create 900 medical safety demonstrations);
        B6 --> B7[/MedSafety-Improve/];
    end

    subgraph Phase["Phase 3: Benchmark Evaluation"]
        B2 --> C1(Evaluate LLMs using MedSafety-Eval datasets);
        C1 --> C2{Score Harmfulness using GPT-3.5};
        C2 --> C3(Analyze results and compare medical vs. general-knowledge LLMs);
        C3 --> C4(Identify that publicly-available medical LLMs do not meet safety standards);
    end

    subgraph Phase["Phase 4: Safety Improvement and Validation"]
        B7 --> D1(Instruction-tune medical LLMs using MedSafety-Improve);
        D1 --> D2(Evaluate fine-tuned models using MedSafety-Eval);
        D2 --> D3{Assess Medical Knowledge};
        D3 --> D4(Evaluate on MedQA, MedMCQA, PubMedQA, MMLU-Medical);
        D4 --> D5(Confirm safety alignment does not degrade medical performance);
        D5 --> D6([End]);
    end

    style A0 fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style D6 fill:#1a1a2e,stroke:#4a90d9,color:#fff
    style A1 fill:#0d3b66,stroke:#4a90d9,color:#fff
