flowchart_en:
flowchart TD
    subgraph Phase["Phase 1: Wild Query Mining"]
        A1([Start]) --> A2[/Common Crawl Splits/];
        A2 --> A3(Detect queries using open-source LLMs trained on self-collected data);
        A3 --> A4{Is it a query?};
        A4 -->|Yes| A5(Filter out non-query sentences using GPT-4 Turbo);
        A4 -->|No| A6(Discard);
        A5 --> A7(Classify queries by input/output modalities);
        A7 --> A8{Is it text-in-text-out?};
        A8 -->|Yes| A9[/Mined Real-World User Queries/];
        A8 -->|No| A10(Discard);
    end

    subgraph Phase["Phase 2: Grounding Existing Benchmarks"]
        B1[/Existing Benchmark Pool/] --> B2(Match each mined query with the most similar query in the benchmark pool);
        B2 --> B3(Retrieve corresponding ground truth answer);
        B3 --> B4[/Initial MixEval Benchmark/];
    end

    subgraph Phase["Phase 3: Creating MixEval-Hard"]
        C1[/Initial MixEval Benchmark/] --> C2(Derive a challenging subset from MixEval);
        C2 --> C3{Is the query challenging?};
        C3 -->|Yes| C4[/MixEval-Hard Benchmark/];
        C3 -->|No| C5(Discard);
    end

    subgraph Phase["Phase 4: Dynamic Evaluation & Quality Control"]
        D1[/MixEval-Hard Benchmark/] --> D2(Periodically update data points with new wild queries);
        D2 --> D3{Low model score variance? (0.36 Std.)};
        D3 -->|Yes| D4{Significant version difference? (85% unique query ratio)};
        D3 -->|No| D5(Re-evaluate and adjust);
        D4 -->|Yes| D6([End]);
        D4 -->|No| D7(Re-evaluate and adjust);
    end

