flowchart_en:
flowchart TD
    subgraph Phase["Phase 1: Data Sourcing"]
        A([Start]) --> B{Select Core Facts};
        B --> C[/WorldTree Corpus/];
        C --> D(Filter 2287 central facts);
        D --> E(Filter down to 1326 general facts);
    end

    subgraph Phase["Phase 2: Question Generation"]
        E --> F{Crowd-worker task};
        F --> G(Worker shown a random fact 'f');
        G --> H(Worker thinks of a common knowledge fact 'k');
        H --> I(Worker combines 'f' and 'k' to a new assertion 's');
        I --> J(Worker converts 's' into a 4-way multiple choice question);
    end

    subgraph Phase["Phase 3: Automated Filtering"]
        J --> K{System Verification};
        K -->|Uniform answer choice length| L(Check passed);
        K -->|No negation words| L;
        K -->|Exactly 4 choices| L;
        L --> M{Hardness Verification};
        M -->|IR solver fails| N(Check passed);
        M -->|Word association solver fails| N;
        N --> O{Sufficient Context Check};
        O -->|Top 3 IR results insufficient| P(Check passed);
    end

    subgraph Phase["Phase 4: Crowd-worker Validation"]
        P --> Q{Crowd-worker validation};
        Q --> R(5 new workers answer the question);
        R --> S{Answerability Check};
        S -->|>= 4/5 correct| T(Deemed answerable);
        S -->|< 4/5 correct| U(Discard question);
    end

    subgraph Phase["Phase 5: Finalization"]
        T --> V(Shuffle answer choices);
        V --> W(Associate question with core fact 'f');
        W --> X(Add to question set Q);
        X --> Y(Add 'k' to auxiliary fact set K);
        Y --> Z([End]);
    end

